mapper.select:
SELECT id, session_id AS sessionId, role, content, meta_json AS metaJson, created_at AS createdAt
FROM chat_message
WHERE session_id = #{sessionId}
ORDER BY created_at ASC, id ASC
LIMIT #{limit}

SELECT id, session_id AS sessionId, role, content, meta_json AS metaJson, created_at AS createdAt
FROM chat_message
WHERE session_id = #{sessionId}

    AND id < #{beforeId}

ORDER BY created_at DESC, id DESC
LIMIT #{limit}
